SELECT  

,creator_id.id as creator_id_id1 
,creator_id.USERNAME as creator_id_USERNAME1 
,creator_id.PASSWORD as creator_id_PASSWORD1 
,creator_id.NAME as creator_id_NAME1 
,creator_id.role_manage_id as creator_id_role_manage_id1 
,creator_id.create_time as creator_id_create_time1 
,creator_id.update_time as creator_id_update_time1 
,creator_id.signature as creator_id_signature1 
,admin_id.id as admin_id_id1 
,admin_id.USERNAME as admin_id_USERNAME1 
,admin_id.PASSWORD as admin_id_PASSWORD1 
,admin_id.NAME as admin_id_NAME1 
,admin_id.role_manage_id as admin_id_role_manage_id1 
,admin_id.create_time as admin_id_create_time1 
,admin_id.update_time as admin_id_update_time1 
,admin_id.signature as admin_id_signature1 
FROM app_team su

left join sys_user creator_id on creator_id.id=su.creator_id
left join sys_user admin_id on admin_id.id=su.admin_id
where 1 = 1
  and su.id = #{id}  
  and su.team_name = #{team_name}  
  and su.creator_id = #{creator_id}  
  and su.admin_id = #{admin_id}  
  and su.description = #{description}  
  and su.status = #{status}  
  and su.audit_status = #{audit_status}  
  and su.create_time = #{create_time}  
  and su.update_time = #{update_time}

SELECT
,creator_id.id as creator_id_id1 ,creator_id.USERNAME as creator_id_USERNAME1 ,creator_id.PASSWORD as creator_id_PASSWORD1 ,creator_id.NAME as creator_id_NAME1 ,creator_id.role_manage_id as creator_id_role_manage_id1 ,creator_id.create_time as creator_id_create_time1 ,creator_id.update_time as creator_id_update_time1 ,creator_id.signature as creator_id_signature1 ,admin_id.id as admin_id_id1 ,admin_id.USERNAME as admin_id_USERNAME1 ,admin_id.PASSWORD as admin_id_PASSWORD1 ,admin_id.NAME as admin_id_NAME1 ,admin_id.role_manage_id as admin_id_role_manage_id1 ,admin_id.create_time as admin_id_create_time1 ,admin_id.update_time as admin_id_update_time1 ,admin_id.signature as admin_id_signature1 FROM app_team su
left join sys_user creator_id on creator_id.id=su.creator_id left join sys_user admin_id on admin_id.id=su.admin_id where 1 = 1 and su.id = #{pd.id} and su.team_name = #{pd.team_name} and su.creator_id = #{pd.creator_id} and su.admin_id = #{pd.admin_id} and su.description = #{pd.description} and su.status = #{pd.status} and su.audit_status = #{pd.audit_status}
and ( CAST(su.creator_id AS CHAR) = CAST(#{pd.scope_user_id} AS CHAR) or CAST(su.admin_id AS CHAR) = CAST(#{pd.scope_user_id} AS CHAR) or exists ( select 1 from app_team_user tu where CAST(tu.team_id AS CHAR)=CAST(su.id AS CHAR) and CAST(tu.user_id AS CHAR)=CAST(#{pd.scope_user_id} AS CHAR) and CAST(IFNULL(tu.status,'') AS CHAR)='1' ) )
and su.create_time = #{pd.create_time} and su.update_time = #{pd.update_time}
